import { useState } from "react";
import { useTranslation } from "react-i18next";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent } from "@/components/ui/card";
import { Textarea } from "@/components/ui/textarea";
import { Upload, X, Plus, ChevronDown, ChevronUp, GripVertical, ImageIcon } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useToast } from "@/hooks/use-toast";
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible";

export interface ScenicSpot {
  id: string;
  titleZh: string;
  titleEn: string;
  titlePt: string;
  descZh: string;
  descEn: string;
  descPt: string;
  image: string;
}

interface LandmarkSpotsEditorProps {
  spots: ScenicSpot[];
  onChange: (spots: ScenicSpot[]) => void;
}

export function LandmarkSpotsEditor({ spots, onChange }: LandmarkSpotsEditorProps) {
  const { t } = useTranslation();
  const { toast } = useToast();
  const [expandedIndex, setExpandedIndex] = useState<number | null>(spots.length > 0 ? 0 : null);
  const [uploadingIndex, setUploadingIndex] = useState<number | null>(null);

  const addSpot = () => {
    const newSpot: ScenicSpot = {
      id: `spot-${Date.now()}`,
      titleZh: "",
      titleEn: "",
      titlePt: "",
      descZh: "",
      descEn: "",
      descPt: "",
      image: "",
    };
    onChange([...spots, newSpot]);
    setExpandedIndex(spots.length);
  };

  const removeSpot = (index: number) => {
    const newSpots = spots.filter((_, i) => i !== index);
    onChange(newSpots);
    if (expandedIndex === index) setExpandedIndex(null);
    else if (expandedIndex !== null && expandedIndex > index) setExpandedIndex(expandedIndex - 1);
  };

  const updateSpot = (index: number, field: keyof ScenicSpot, value: string) => {
    const newSpots = [...spots];
    newSpots[index] = { ...newSpots[index], [field]: value };
    onChange(newSpots);
  };

  // Single input syncs to all three language fields
  const updateSpotAll = (index: number, base: "title" | "desc", value: string) => {
    const newSpots = [...spots];
    newSpots[index] = {
      ...newSpots[index],
      [`${base}Zh`]: value,
      [`${base}En`]: value,
      [`${base}Pt`]: value,
    } as any;
    onChange(newSpots);
  };

  const moveSpot = (index: number, direction: "up" | "down") => {
    const newIndex = direction === "up" ? index - 1 : index + 1;
    if (newIndex < 0 || newIndex >= spots.length) return;
    const newSpots = [...spots];
    [newSpots[index], newSpots[newIndex]] = [newSpots[newIndex], newSpots[index]];
    onChange(newSpots);
    setExpandedIndex(newIndex);
  };

  const handleImageUpload = async (index: number, file: File) => {
    setUploadingIndex(index);
    try {
      const fileExt = file.name.split(".").pop();
      const fileName = `landmark_spot_${Date.now()}_${Math.random().toString(36).slice(2)}.${fileExt}`;
      const { error: uploadError } = await supabase.storage
        .from("restaurant-images")
        .upload(fileName, file);
      if (uploadError) throw uploadError;
      const { data: { publicUrl } } = supabase.storage
        .from("restaurant-images")
        .getPublicUrl(fileName);
      updateSpot(index, "image", publicUrl);
      toast({ title: t("common.success"), description: "图片上传成功" });
    } catch (err: any) {
      toast({ title: t("common.error"), description: err.message, variant: "destructive" });
    } finally {
      setUploadingIndex(null);
    }
  };

  return (
    <div className="space-y-3">
      <div className="flex items-center justify-between">
        <Label className="text-sm font-medium">
          {t("admin.scenicSpots", "代表景点")} ({spots.length})
        </Label>
        <Button type="button" variant="outline" size="sm" onClick={addSpot} className="gap-1.5">
          <Plus className="w-3.5 h-3.5" />
          {t("admin.addSpot", "添加景点")}
        </Button>
      </div>

      {spots.length === 0 && (
        <div className="text-center py-8 border-2 border-dashed rounded-lg text-muted-foreground">
          <ImageIcon className="w-8 h-8 mx-auto mb-2 opacity-50" />
          <p className="text-sm">{t("admin.noSpots", "暂无景点，点击上方按钮添加")}</p>
        </div>
      )}

      {spots.map((spot, index) => (
        <Collapsible
          key={spot.id}
          open={expandedIndex === index}
          onOpenChange={(open) => setExpandedIndex(open ? index : null)}
        >
          <Card className="border-border/60">
            <CollapsibleTrigger asChild>
              <div className="flex items-center gap-2 p-3 cursor-pointer hover:bg-muted/30 transition-colors">
                <GripVertical className="w-4 h-4 text-muted-foreground shrink-0" />
                {spot.image ? (
                  <img src={spot.image} alt="" className="w-10 h-10 rounded object-cover shrink-0" />
                ) : (
                  <div className="w-10 h-10 rounded bg-muted flex items-center justify-center shrink-0">
                    <ImageIcon className="w-4 h-4 text-muted-foreground" />
                  </div>
                )}
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium truncate">
                    {spot.titleZh || spot.titleEn || `景点 ${index + 1}`}
                  </p>
                  <p className="text-xs text-muted-foreground truncate">
                    {spot.descZh || spot.descEn || "未填写描述"}
                  </p>
                </div>
                <div className="flex items-center gap-1 shrink-0">
                  <Button type="button" variant="ghost" size="icon" className="h-7 w-7" onClick={(e) => { e.stopPropagation(); moveSpot(index, "up"); }} disabled={index === 0}>
                    <ChevronUp className="w-3.5 h-3.5" />
                  </Button>
                  <Button type="button" variant="ghost" size="icon" className="h-7 w-7" onClick={(e) => { e.stopPropagation(); moveSpot(index, "down"); }} disabled={index === spots.length - 1}>
                    <ChevronDown className="w-3.5 h-3.5" />
                  </Button>
                  <Button type="button" variant="ghost" size="icon" className="h-7 w-7 text-destructive hover:text-destructive" onClick={(e) => { e.stopPropagation(); removeSpot(index); }}>
                    <X className="w-3.5 h-3.5" />
                  </Button>
                </div>
              </div>
            </CollapsibleTrigger>
            <CollapsibleContent>
              <CardContent className="p-4 pt-0 space-y-4 border-t">
                {/* Image */}
                <div className="space-y-2">
                  <Label className="text-xs font-medium text-muted-foreground">{t("admin.spotImage", "景点图片")}</Label>
                  <div className="flex items-start gap-3">
                    {spot.image && (
                      <div className="relative group">
                        <img src={spot.image} alt="" className="w-24 h-16 object-cover rounded-lg ring-1 ring-border" />
                        <Button type="button" variant="destructive" size="icon" className="absolute -top-1.5 -right-1.5 h-5 w-5 rounded-full opacity-0 group-hover:opacity-100 transition-opacity" onClick={() => updateSpot(index, "image", "")}>
                          <X className="h-2.5 w-2.5" />
                        </Button>
                      </div>
                    )}
                    <Label htmlFor={`spot-image-${index}`} className="cursor-pointer">
                      <div className="flex flex-col items-center gap-1.5 px-4 py-2 border-2 border-dashed border-primary/30 rounded-lg hover:border-primary hover:bg-primary/5 transition-all">
                        <Upload className="h-4 w-4 text-primary" />
                        <span className="text-xs font-medium">{uploadingIndex === index ? "上传中..." : "上传"}</span>
                      </div>
                      <Input
                        id={`spot-image-${index}`}
                        type="file"
                        accept="image/*"
                        className="hidden"
                        disabled={uploadingIndex === index}
                        onChange={(e) => {
                          const file = e.target.files?.[0];
                          if (file) handleImageUpload(index, file);
                        }}
                      />
                    </Label>
                    <div className="flex-1">
                      <Input
                        placeholder="或粘贴图片URL..."
                        value={spot.image}
                        onChange={(e) => updateSpot(index, "image", e.target.value)}
                        className="h-8 text-xs"
                      />
                    </div>
                  </div>
                </div>

                {/* Title */}
                <div className="space-y-1">
                  <Label className="text-xs text-muted-foreground">名称 / Name</Label>
                  <Input value={spot.titleZh || spot.titleEn || ""} onChange={(e) => updateSpotAll(index, "title", e.target.value)} placeholder="象鼻山 / Elephant Trunk Hill" className="h-8 text-sm" />
                </div>

                {/* Description */}
                <div className="space-y-1">
                  <Label className="text-xs text-muted-foreground">简介 / Description</Label>
                  <Textarea value={spot.descZh || spot.descEn || ""} onChange={(e) => updateSpotAll(index, "desc", e.target.value)} placeholder="桂林城市徽标... / Guilin's iconic emblem..." rows={2} className="text-sm resize-none" />
                </div>
              </CardContent>
            </CollapsibleContent>
          </Card>
        </Collapsible>
      ))}
    </div>
  );
}
