import { useTranslation } from "react-i18next";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";

export interface LandmarkInfo {
  subtitleZh?: string;
  subtitleEn?: string;
  subtitlePt?: string;
  bestSeasonZh?: string;
  bestSeasonEn?: string;
  bestSeasonPt?: string;
  durationZh?: string;
  durationEn?: string;
  durationPt?: string;
  altitude?: string;
  geologyZh?: string;
  geologyEn?: string;
  geologyPt?: string;
}

interface LandmarkInfoEditorProps {
  info: LandmarkInfo;
  onChange: (info: LandmarkInfo) => void;
}

export function LandmarkInfoEditor({ info, onChange }: LandmarkInfoEditorProps) {
  const { t } = useTranslation();

  // Single input syncs to all three language fields
  const updateAll = (base: string, value: string) => {
    onChange({
      ...info,
      [`${base}Zh`]: value,
      [`${base}En`]: value,
      [`${base}Pt`]: value,
    });
  };

  const update = (field: keyof LandmarkInfo, value: string) => {
    onChange({ ...info, [field]: value });
  };

  return (
    <div className="space-y-4">
      {/* Subtitle */}
      <div className="space-y-2">
        <Label className="text-sm font-medium">{t("admin.landmarkSubtitle", "景点副标题")}</Label>
        <p className="text-xs text-muted-foreground">显示在景点概述卡片中的副标题</p>
        <Input
          value={info.subtitleZh || info.subtitleEn || ""}
          onChange={(e) => updateAll("subtitle", e.target.value)}
          placeholder="世界自然遗产 · 喀斯特地貌 / World Natural Heritage"
          className="h-8 text-sm"
        />
      </div>

      {/* Visitor Info Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {/* Best Season */}
        <div className="space-y-2">
          <Label className="text-sm font-medium">{t("admin.bestSeason", "最佳季节")}</Label>
          <Input
            value={info.bestSeasonZh || info.bestSeasonEn || ""}
            onChange={(e) => updateAll("bestSeason", e.target.value)}
            placeholder="4月-10月 / Apr - Oct"
            className="h-8 text-sm"
          />
        </div>

        {/* Duration */}
        <div className="space-y-2">
          <Label className="text-sm font-medium">{t("admin.visitDuration", "建议游览时间")}</Label>
          <Input
            value={info.durationZh || info.durationEn || ""}
            onChange={(e) => updateAll("duration", e.target.value)}
            placeholder="2-4天 / 2-4 days"
            className="h-8 text-sm"
          />
        </div>

        {/* Altitude */}
        <div className="space-y-2">
          <Label className="text-sm font-medium">{t("admin.altitude", "海拔")}</Label>
          <Input value={info.altitude || ""} onChange={(e) => update("altitude", e.target.value)} placeholder="150-1,100m" className="h-8 text-sm" />
        </div>

        {/* Geology */}
        <div className="space-y-2">
          <Label className="text-sm font-medium">{t("admin.geology", "地貌类型")}</Label>
          <Input
            value={info.geologyZh || info.geologyEn || ""}
            onChange={(e) => updateAll("geology", e.target.value)}
            placeholder="喀斯特 / Karst"
            className="h-8 text-sm"
          />
        </div>
      </div>
    </div>
  );
}
